396: void UdpProxyFilter::UdpActiveSession::onReadReady() {
397:   resetIdleTimer();
398: 
399:   // TODO(mattklein123): We should not be passing *addresses_.local_ to this function as we are
400:   //                     not trying to populate the local address for received packets.
401:   uint32_t packets_dropped = 0;
402:   const Api::IoErrorPtr result = Network::Utility::readPacketsFromSocket(
403:       udp_socket_->ioHandle(), *addresses_.local_, *this, cluster_.filter_.config_->timeSource(),
404:       cluster_.filter_.config_->upstreamSocketConfig().prefer_gro_, /*allow_mmsg=*/true,
405:       packets_dropped);
