538: bool UdpProxyFilter::UdpActiveSession::createUpstream() {
539:   if (udp_socket_) {
540:     // A session filter may call on continueFilterChain(), after already creating the socket,
541:     // so we first check that the socket was not created already.
542:     return true;
543:   }
544: 
545:   if (!host_) {
546:     host_ = cluster_.chooseHost(addresses_.peer_, &udp_session_info_);
547:     if (host_ == nullptr) {
548:       ENVOY_LOG(debug, "cannot find any valid host.");
549:       cluster_.cluster_.info()->trafficStats()->upstream_cx_none_healthy_.inc();
550:       return false;
551:     }
552:   }
553: 
554:   udp_session_info_.upstreamInfo()->setUpstreamHost(host_);
555:   cluster_.addSession(host_.get(), this);
556:   createUdpSocket(host_);
557:   return true;
558: }
