673:   if (!rc.ok()) {
674:     cluster_.filter_.config_->stats().downstream_sess_tx_errors_.inc();
675:     ++session_stats_.downstream_sess_tx_errors_;
676:   } else {
677:     cluster_.filter_.config_->stats().downstream_sess_tx_bytes_.add(tx_buffer_length);
678:     session_stats_.downstream_sess_tx_bytes_ += tx_buffer_length;
679:     cluster_.filter_.config_->stats().downstream_sess_tx_datagrams_.inc();
