761: const std::string HttpUpstreamImpl::resolveTargetTunnelPath() {
762:   std::string target_host = tunnel_config_.targetHost(downstream_info_);
763:   target_host = Http::Utility::PercentEncoding::encode(target_host, ":");
764: 
765:   const auto* dynamic_port =
766:       downstream_info_.filterState()->getDataReadOnly<StreamInfo::UInt32Accessor>(
767:           "udp.connect.target_port");
768: 
769:   std::string target_port;
770:   if (dynamic_port != nullptr && dynamic_port->value() > 0 && dynamic_port->value() <= 65535) {
771:     target_port = std::to_string(dynamic_port->value());
772:   } else {
773:     target_port = std::to_string(tunnel_config_.defaultTargetPort());
774:   }
775: 
776:   // TODO(ohadvano): support configurable URI template.
777:   return absl::StrCat("/.well-known/masque/udp/", target_host, "/", target_port, "/");
778: }
