// Verify that cluster_infos_ map is correctly updated when a cluster is updated via CDS/EDS.
TEST_F(UdpProxyFilterTest, ClusterDynamicInfoMapUpdate) {
  InSequence s;

  setup(readConfig(R"EOF(
stat_prefix: foo
matcher:
  on_no_match:
    action:
      name: route
      typed_config:
        '@type': type.googleapis.com/envoy.extensions.filters.udp.udp_proxy.v3.Route
        cluster: fake_cluster
  )EOF"));

  expectSessionCreate(upstream_address_);
  test_sessions_[0].expectWriteToUpstream("hello", 0, nullptr, true);
  recvDataFromDownstream("10.0.0.1:1000", "10.0.0.2:80", "hello");
  EXPECT_EQ(1, config_->stats().downstream_sess_total_.value());
  EXPECT_EQ(1, config_->stats().downstream_sess_active_.value());

  // Simulate a CDS update: call onClusterAddOrUpdate() with the same cluster name
  // but a new cluster object. With the bug (emplace), this would silently fail and
  // leave a stale ClusterInfo. With the fix (insert_or_assign), the map is updated.
  NiceMock<Upstream::MockThreadLocalCluster> new_thread_local_cluster;
  new_thread_local_cluster.cluster_.info_->name_ = "fake_cluster";
  ON_CALL(*new_thread_local_cluster.lb_.host_, address()).WillByDefault(Return(upstream_address_));
  ON_CALL(*new_thread_local_cluster.lb_.host_, coarseHealth())
      .WillByDefault(Return(Upstream::Host::Health::Healthy));
  {
    Upstream::ThreadLocalClusterCommand command =
        [&new_thread_local_cluster]() -> Upstream::ThreadLocalCluster& {
      return new_thread_local_cluster;
    };
    cluster_update_callbacks_->onClusterAddOrUpdate(new_thread_local_cluster.info()->name(),
                                                    command);
  }
  // The old ClusterInfo is replaced, so all old sessions are cleaned up.
  EXPECT_EQ(0, config_->stats().downstream_sess_active_.value());

  // Verify the filter works with the new cluster.
  expectSessionCreate(upstream_address_);
  test_sessions_[1].expectWriteToUpstream("hello", 0, nullptr, true);
  recvDataFromDownstream("10.0.0.2:1000", "10.0.0.2:80", "hello");
  EXPECT_EQ(2, config_->stats().downstream_sess_total_.value());
  EXPECT_EQ(1, config_->stats().downstream_sess_active_.value());
}

