  EXPECT_CALL(creation_callbacks_, onStreamSuccess(_));
  EXPECT_CALL(callbacks_, onUpstreamData(_, _))
      .WillOnce(Invoke([](Buffer::Instance&, bool end_stream) { EXPECT_FALSE(end_stream); }))
