  EXPECT_CALL(*config_, proxyHost(_)).WillRepeatedly(Return("proxy.host"));
  EXPECT_CALL(*config_, proxyPort()).WillRepeatedly(ReturnRef(port));
  EXPECT_CALL(*config_, targetHost(_)).WillRepeatedly(Return("target.host"));
